  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsAnalyzing(true);
    // In a real app, we'd convert the drawing to image/base64 here
    try {
        // Simulating some delay for dramatic effect/UI
        await new Promise(r => setTimeout(r, 2000));
        // We call geminiService.analyzeDrawing(base64Data, project.buildingType)
        setBoqData(MOCK_BOQ); 
    } finally {
        setIsAnalyzing(false);
    }
  };

  /* Fixed audio playback to handle raw PCM from Gemini TTS using AudioContext */
  const handleVoiceExplanation = async () => {
    setIsPlayingAudio(true);
    const summary = `Project ${project.name} is a ${project.floors}-floor ${project.buildingType} building. The total BOQ value is calculated at approximately ${boqData.reduce((a, b) => a + b.total, 0)} dollars. High risk areas include steel estimation due to lack of BBS drawings.`;

    try {
      const audioBase64 = await geminiService.generateSpeech(summary);

      if (audioBase64) {
        // Raw PCM requires AudioContext to decode and play correctly as per guidelines
        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const decodedBytes = decodeBase64(audioBase64);
        const audioBuffer = await decodeAudioData(decodedBytes, audioContext, 24000, 1);

        const source = audioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContext.destination);

        source.onended = () => {
          setIsPlayingAudio(false);
        };

        source.start();
      } else {
        setIsPlayingAudio(false);
      }
    } catch (error) {
      console.error("Failed to generate or play speech:", error);
      setIsPlayingAudio(false);
    }
  };

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
