    { id: 's1', barMark: 'B1-01', diameter: 16, spacing: 150, shape: 'Straight', totalWeight: 1.2 },
    { id: 's2', barMark: 'C1-04', diameter: 20, spacing: 200, shape: 'Bent-up', totalWeight: 2.8 },
    { id: 's3', barMark: 'S1-Top', diameter: 10, spacing: 100, shape: 'L-Hook', totalWeight: 0.8 },
  ]);

  const COLORS = ['#4f46e5', '#10b981', '#f59e0b', '#ef4444', '#6366f1'];
  const costBreakdown = boqData.map(item => ({ name: item.category, value: item.total }));

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsAnalyzing(true);
    setUploadProgress(0);
    setAnalysisStatus(['Initializing CAD engine...']);

    const steps = [
      { msg: 'Detecting structural layers...', progress: 20 },
      { msg: 'Identifying load-bearing walls...', progress: 40 },
      { msg: 'Calculating slab areas...', progress: 60 },
      { msg: 'Estimating reinforcement volumes...', progress: 80 },
      { msg: 'Finalizing construction intelligence...', progress: 100 },
