export const ProjectDetails: React.FC<ProjectDetailsProps> = ({ project, onBack, userRole }) => {
  const [activeSubTab, setActiveSubTab] = useState<'boq' | 'steel' | 'costs' | 'errors' | 'what-if'>('boq');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [analysisPhase, setAnalysisPhase] = useState('');
  const [boqData, setBoqData] = useState<BOQItem[]>(MOCK_BOQ);
  const [steelDetails, setSteelDetails] = useState<SteelDetail[]>(MOCK_STEEL_DETAILS);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);
  const [showExportModal, setShowExportModal] = useState(false);
  const [exportOptions, setExportOptions] = useState({ format: 'pdf', columns: ['Description', 'Quantity', 'Rate', 'Total'] });

  const COLORS = ['#4F46E5', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6'];

  const getCostData = () => {
    const categories: Record<string, number> = {};
    boqData.forEach(item => {
      categories[item.category] = (categories[item.category] || 0) + item.total;
    });
    return Object.entries(categories).map(([name, value]) => ({ name, value }));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsAnalyzing(true);
    setUploadProgress(0);

    const phases = [
      { msg: 'Detecting walls and columns...', progress: 20 },
      { msg: 'Calculating slab and wall areas...', progress: 45 },
      { msg: 'Estimating material volumes...', progress: 70 },
      { msg: 'Detecting structural inconsistencies...', progress: 90 },
      { msg: 'Finalizing intelligence report...', progress: 100 },
    ];

    for (const phase of phases) {
      setAnalysisPhase(phase.msg);
      await new Promise(r => setTimeout(r, 800 + Math.random() * 500));
      setUploadProgress(phase.progress);
    }

    setTimeout(() => {
      setIsAnalyzing(false);
      setBoqData(MOCK_BOQ); 
    }, 500);
  };

  const handleVoiceExplanation = async () => {
    setIsPlayingAudio(true);
    const summaryText = `Analyzing project ${project.name}. As a ${userRole}, note that concrete volume is high due to deep footings. Confidence for steel is lower, around 85 percent, because specific reinforcement drawings are needed for detail refinement.`;
    try {
      const audioBase64 = await geminiService.generateSpeech(summaryText);
      if (audioBase64) {
        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const decodedBytes = decodeBase64(audioBase64);
        const audioBuffer = await decodeAudioData(decodedBytes, audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContext.destination);
        source.onended = () => setIsPlayingAudio(false);
        source.start();
      } else {
        setIsPlayingAudio(false);
      }
    } catch (e) {
      console.error(e);
      setIsPlayingAudio(false);
    }
  };

