import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { ProjectDetails } from './components/ProjectDetails';
import { MentorBot } from './components/MentorBot';
import { Project, UserRole } from './types';
import { MOCK_PROJECTS } from './constants';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [selectedProject, setSelectedProject] = useState<Project | null>(null);
  const [userRole, setUserRole] = useState<UserRole>('Civil Engineer');
  const [projects, setProjects] = useState<Project[]>(MOCK_PROJECTS);

  const handleProjectSelect = (projectId: string) => {
    const prj = projects.find(p => p.id === projectId);
    if (prj) {
      setSelectedProject(prj);
      setActiveTab('project-view');
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard 
          projects={projects} 
          onSelectProject={handleProjectSelect}
          userRole={userRole}
        />;
      case 'project-view':
        return selectedProject ? (
          <ProjectDetails 
            project={selectedProject} 
            onBack={() => setActiveTab('dashboard')} 
            userRole={userRole}
          />
        ) : null;
      case 'mentorship':
        return <MentorBot userRole={userRole} />;
      case 'projects':
        return <Dashboard 
          projects={projects} 
          onSelectProject={handleProjectSelect}
          userRole={userRole}
        />;
      default:
        return (
          <div className="p-16 flex flex-col items-center justify-center text-slate-400 space-y-4">
             <div className="w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center">
                <Settings size={32} />
             </div>
             <p className="font-bold uppercase tracking-widest text-xs">Section Under Maintenance</p>
          </div>
        );
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      onTabChange={setActiveTab}
      userRole={userRole}
      setUserRole={setUserRole}
    >
      <div className="animate-in fade-in duration-700">
        {renderContent()}
      </div>
    </Layout>
  );
};

export default App;

const Settings = ({ className, size = 24 }: { className?: string, size?: number }) => (
  <svg className={className} width={size} height={size} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z" />
    <path strokeLinecap="round" strokeLinejoin="round" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
  </svg>
);

import React, { useState, useEffect } from 'react';
import { Project, BOQItem, DesignError, SteelDetail } from '../types';
import { 
  ArrowLeft, Upload, FileText, Activity, ShieldAlert, Cpu, 
  Volume2, Download, Package, PieChart as PieChartIcon, 
  Settings, X, Check, Save, Share2, FileJson, FileType, CheckCircle,
  Plus
} from 'lucide-react';
import { BOQTable } from './BOQTable';
import { ErrorDetector } from './ErrorDetector';
import { WhatIfSimulator } from './WhatIfSimulator';
import { geminiService, decodeBase64, decodeAudioData } from '../services/gemini';
import { MOCK_BOQ, MOCK_STEEL_DETAILS } from '../constants';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface ProjectDetailsProps {
  project: Project;
  onBack: () => void;
  userRole: string;
}

export const ProjectDetails: React.FC<ProjectDetailsProps> = ({ project, onBack, userRole }) => {
  const [activeSubTab, setActiveSubTab] = useState<'boq' | 'steel' | 'costs' | 'errors' | 'what-if'>('boq');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [analysisPhase, setAnalysisPhase] = useState('');
  const [boqData, setBoqData] = useState<BOQItem[]>(MOCK_BOQ);
  const [steelDetails, setSteelDetails] = useState<SteelDetail[]>(MOCK_STEEL_DETAILS);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);
  const [showExportModal, setShowExportModal] = useState(false);
  const [exportOptions, setExportOptions] = useState({ format: 'pdf', columns: ['Description', 'Quantity', 'Rate', 'Total'] });

  const COLORS = ['#4F46E5', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6'];

  const getCostData = () => {
    const categories: Record<string, number> = {};
    boqData.forEach(item => {
      categories[item.category] = (categories[item.category] || 0) + item.total;
    });
    return Object.entries(categories).map(([name, value]) => ({ name, value }));
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsAnalyzing(true);
    setUploadProgress(0);

    const phases = [
      { msg: 'Detecting walls and columns...', progress: 20 },
      { msg: 'Calculating slab and wall areas...', progress: 45 },
      { msg: 'Estimating material volumes...', progress: 70 },
      { msg: 'Detecting structural inconsistencies...', progress: 90 },
      { msg: 'Finalizing intelligence report...', progress: 100 },
    ];

    for (const phase of phases) {
      setAnalysisPhase(phase.msg);
      await new Promise(r => setTimeout(r, 800 + Math.random() * 500));
      setUploadProgress(phase.progress);
    }

    setTimeout(() => {
      setIsAnalyzing(false);
      setBoqData(MOCK_BOQ); 
    }, 500);
  };

  const handleVoiceExplanation = async () => {
    setIsPlayingAudio(true);
    const summaryText = `Analyzing project ${project.name}. As a ${userRole}, note that concrete volume is high due to deep footings. Confidence for steel is lower, around 85 percent, because specific reinforcement drawings are needed for detail refinement.`;
    try {
      const audioBase64 = await geminiService.generateSpeech(summaryText);
      if (audioBase64) {
        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const decodedBytes = decodeBase64(audioBase64);
        const audioBuffer = await decodeAudioData(decodedBytes, audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContext.destination);
        source.onended = () => setIsPlayingAudio(false);
        source.start();
      } else {
        setIsPlayingAudio(false);
      }
    } catch (e) {
      console.error(e);
      setIsPlayingAudio(false);
    }
  };

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400 hover:text-indigo-600">
            <ArrowLeft size={24} />
          </button>
          <div>
            <h2 className="text-3xl font-bold text-slate-900 tracking-tight">{project.name}</h2>
            <div className="flex items-center gap-2 text-slate-500 text-sm font-medium">
              <span>{project.location}</span>
              <span>&bull;</span>
              <span className="bg-indigo-50 text-indigo-700 px-2 py-0.5 rounded text-xs font-bold uppercase">{userRole} MODE</span>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
           <button 
             onClick={handleVoiceExplanation}
             disabled={isPlayingAudio}
             className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-sm font-bold border transition-all ${isPlayingAudio ? 'bg-indigo-600 border-indigo-600 text-white shadow-indigo-200' : 'bg-white border-slate-200 text-slate-700 hover:border-indigo-300 shadow-sm'}`}
           >
             <Volume2 size={20} className={isPlayingAudio ? 'animate-pulse' : ''} />
             {isPlayingAudio ? 'Speaking...' : 'Explain drawing'}
           </button>
           <button 
             onClick={() => setShowExportModal(true)}
             className="flex items-center gap-2 px-5 py-2.5 rounded-xl bg-slate-900 text-white text-sm font-bold hover:bg-slate-800 shadow-xl transition-all"
           >
             <Download size={20} />
             Export BOQ
           </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Drawing Sidebar */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-2 rounded-2xl border border-slate-200 shadow-sm aspect-square relative group overflow-hidden">
            {isAnalyzing && (
              <div className="absolute inset-0 z-20 bg-slate-900/60 backdrop-blur-md flex flex-col items-center justify-center text-white p-6 text-center">
                <div className="relative w-20 h-20 mb-4">
                   <Cpu className="w-full h-full animate-spin text-indigo-400 opacity-40" />
                   <div className="absolute inset-0 flex items-center justify-center font-bold text-lg text-indigo-300">
                     {uploadProgress}%
                   </div>
                </div>
                <p className="font-bold text-sm tracking-widest uppercase mb-1">{analysisPhase}</p>
                <div className="w-full bg-slate-700 h-1.5 rounded-full mt-4 overflow-hidden border border-slate-600">
                  <div className="h-full bg-indigo-500 transition-all duration-300" style={{ width: `${uploadProgress}%` }} />
                </div>
              </div>
            )}
            <img 
              src={project.drawingUrl || 'https://picsum.photos/600/600'} 
              className="w-full h-full object-cover rounded-xl shadow-inner"
            />
            <div className="absolute inset-0 bg-slate-900/40 opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center">
               <label className="cursor-pointer bg-white text-slate-900 text-xs font-black px-6 py-3 rounded-xl shadow-2xl hover:scale-105 transition-transform">
                  <input type="file" className="hidden" onChange={handleFileUpload} accept=".dwg,.dxf,.jpg,.png" />
                  REPLACE DRAWING
               </label>
            </div>
          </div>

          <div className="bg-slate-900 rounded-2xl p-6 text-white space-y-6">
            <h4 className="text-xs font-bold text-indigo-400 uppercase tracking-widest">Structural Insights</h4>
            <div className="space-y-4">
               {[
                 { label: 'Layering', status: 'Optimized', icon: <CheckCircle className="text-green-400 w-4 h-4" /> },
                 { label: 'Dimensions', status: 'IS Compliant', icon: <CheckCircle className="text-green-400 w-4 h-4" /> },
                 { label: 'BOQ Reliability', status: 'High (94%)', icon: <CheckCircle className="text-green-400 w-4 h-4" /> },
               ].map((item, i) => (
                 <div key={i} className="flex items-center justify-between text-xs">
                   <span className="text-slate-400 font-medium">{item.label}</span>
                   <div className="flex items-center gap-2">
                     <span className="font-bold">{item.status}</span>
                     {item.icon}
                   </div>
                 </div>
               ))}
            </div>
            <button className="w-full bg-indigo-600 py-3 rounded-xl font-bold text-xs hover:bg-indigo-500 transition-all shadow-lg shadow-indigo-500/20">
              OPTIMIZE DESIGN
            </button>
          </div>
        </div>

        {/* Dynamic Content Tabs */}
        <div className="lg:col-span-3 space-y-6">
          <div className="flex bg-slate-100 p-1 rounded-2xl w-fit overflow-x-auto">
            {[
              { id: 'boq', label: 'Quantities', icon: <FileText size={18} /> },
              { id: 'steel', label: 'Steel Details', icon: <Package size={18} /> },
              { id: 'costs', label: 'Cost Analysis', icon: <PieChartIcon size={18} /> },
              { id: 'errors', label: 'Design Alerts', icon: <ShieldAlert size={18} /> },
              { id: 'what-if', label: 'What-If', icon: <Activity size={18} /> },
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveSubTab(tab.id as any)}
                className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all whitespace-nowrap ${
                  activeSubTab === tab.id ? 'bg-white text-indigo-600 shadow-md' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                {tab.icon}
                {tab.label}
              </button>
            ))}
          </div>

          <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden min-h-[500px]">
            {activeSubTab === 'boq' && <BOQTable items={boqData} />}

            {activeSubTab === 'steel' && (
              <div className="p-8 space-y-8 animate-in slide-in-from-right-4 duration-300">
                <div className="flex justify-between items-start">
                  <div>
                    <h3 className="text-xl font-bold text-slate-800">Reinforcement Detailing (BBS)</h3>
                    <p className="text-sm text-slate-500 font-medium mt-1">Refined steel quantity based on bar-mark extraction.</p>
                  </div>
                  <div className="flex gap-2">
                    {/* Fixed: Added Plus icon from lucide-react */}
                    <button className="flex items-center gap-2 bg-slate-900 text-white px-4 py-2 rounded-xl text-xs font-bold hover:bg-slate-800 shadow-lg">
                      <Plus size={16} /> ADD BAR
                    </button>
                    <label className="cursor-pointer flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-xl text-xs font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100">
                      <input type="file" className="hidden" />
                      <Upload size={16} /> UPLOAD BBS
                    </label>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                   <div className="bg-indigo-50 border border-indigo-100 p-6 rounded-2xl">
                      <div className="flex justify-between items-center mb-4">
                        <p className="text-[10px] font-bold text-indigo-400 uppercase tracking-widest">Total Steel Weight</p>
                        <Package className="text-indigo-300" size={24} />
                      </div>
                      <h4 className="text-2xl font-black text-indigo-700">4.5 MT</h4>
                      <p className="text-[10px] text-indigo-400 font-bold mt-2">+5% Lap Allowance</p>
                   </div>
                   <div className="bg-green-50 border border-green-100 p-6 rounded-2xl">
                      <div className="flex justify-between items-center mb-4">
                        <p className="text-[10px] font-bold text-green-400 uppercase tracking-widest">BBS Confidence</p>
                        <CheckCircle className="text-green-300" size={24} />
                      </div>
                      <h4 className="text-2xl font-black text-green-700">97.2%</h4>
                      <p className="text-[10px] text-green-400 font-bold mt-2">Verified via AI-BarMark</p>
                   </div>
                   <div className="bg-amber-50 border border-amber-100 p-6 rounded-2xl">
                      <div className="flex justify-between items-center mb-4">
                        <p className="text-[10px] font-bold text-amber-400 uppercase tracking-widest">Steel Intensity</p>
                        <TrendingUp className="text-amber-300" size={24} />
                      </div>
                      <h4 className="text-2xl font-black text-amber-700">82 kg/m³</h4>
                      <p className="text-[10px] text-amber-400 font-bold mt-2">Within Standard Range</p>
                   </div>
                </div>

                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b border-slate-200">
                    <tr>
                      <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Bar Mark</th>
                      <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest">Diameter (mm)</th>
                      <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Spacing</th>
                      <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-center">Shape</th>
                      <th className="px-6 py-4 text-[10px] font-bold text-slate-400 uppercase tracking-widest text-right">Weight (MT)</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    {steelDetails.map(bar => (
                      <tr key={bar.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-6 py-4 text-sm font-bold text-slate-800">{bar.barMark}</td>
                        <td className="px-6 py-4 text-sm font-medium text-slate-600">{bar.diameter}mm</td>
                        <td className="px-6 py-4 text-sm font-medium text-slate-600 text-center">{bar.spacing}mm c/c</td>
                        <td className="px-6 py-4 text-center">
                          <span className="bg-slate-100 text-[10px] font-bold uppercase px-2 py-1 rounded">{bar.shape}</span>
                        </td>
                        <td className="px-6 py-4 text-sm font-black text-indigo-600 text-right">{bar.totalWeight.toFixed(2)}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}

            {activeSubTab === 'costs' && (
              <div className="p-8 space-y-8 animate-in slide-in-from-right-4 duration-300">
                <div className="flex justify-between items-center">
                  <h3 className="text-xl font-bold text-slate-800">Material Cost Breakdown</h3>
                  <div className="bg-green-100 text-green-700 text-xs font-bold px-3 py-1.5 rounded-full border border-green-200 flex items-center gap-2">
                    <TrendingUp size={14} />
                    AI INSIGHT: Switch to Fly-Ash bricks for 12% masonry savings
                  </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 items-center">
                   <div className="h-80 bg-slate-50 rounded-2xl border border-slate-100 p-4">
                      <ResponsiveContainer width="100%" height="100%">
                         <PieChart>
                            <Pie
                              data={getCostData()}
                              cx="50%"
                              cy="50%"
                              innerRadius={60}
                              outerRadius={100}
                              paddingAngle={5}
                              dataKey="value"
                            >
                              {getCostData().map((entry, index) => (
                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                              ))}
                            </Pie>
                            <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                            <Legend verticalAlign="bottom" height={36}/>
                         </PieChart>
                      </ResponsiveContainer>
                   </div>
                   <div className="space-y-4">
                      <h4 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Cost-Saving Opportunities</h4>
                      {[
                        { title: 'Concrete Volume Reduction', desc: 'Optimize slab thickness in non-critical spans to save ~12 m³.', icon: <Package className="text-indigo-500" /> },
                        { title: 'Steel Grade Switching', desc: 'Using Fe550 instead of Fe500 reduces weight by 8% in high-load columns.', icon: <ShieldAlert className="text-amber-500" /> },
                        { title: 'Labor Schedule', desc: 'Concurrent excavation for footing pockets can reduce machine rent by 15%.', icon: <Activity className="text-blue-500" /> },
                      ].map((opp, i) => (
                        <div key={i} className="flex gap-4 p-5 bg-white border border-slate-200 rounded-2xl hover:border-indigo-300 transition-colors cursor-default">
                           <div className="p-2 bg-slate-50 rounded-xl h-fit">{opp.icon}</div>
                           <div>
                             <p className="text-sm font-bold text-slate-800">{opp.title}</p>
                             <p className="text-xs text-slate-500 mt-1">{opp.desc}</p>
                           </div>
                        </div>
                      ))}
                   </div>
                </div>
              </div>
            )}

            {activeSubTab === 'errors' && <ErrorDetector errors={[]} />}
            {activeSubTab === 'what-if' && <WhatIfSimulator currentBOQ={boqData} />}
          </div>
        </div>
      </div>

      {/* Enhanced Export Modal */}
      {showExportModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm animate-in fade-in duration-300">
          <div className="bg-white w-full max-w-md rounded-3xl overflow-hidden shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-lg font-bold text-slate-800">Export Parameters</h3>
              <button onClick={() => setShowExportModal(false)} className="text-slate-400 hover:text-indigo-600 p-1">
                <X size={24} />
              </button>
            </div>
            <div className="p-8 space-y-8">
              <div className="space-y-4">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Select Format</label>
                <div className="grid grid-cols-2 gap-3">
                  {[
                    { id: 'pdf', label: 'PDF Document', icon: <FileType size={18} /> },
                    { id: 'xlsx', label: 'Excel Spreadsheet', icon: <Download size={18} /> },
                    { id: 'csv', label: 'CSV Data', icon: <FileText size={18} /> },
                    { id: 'json', label: 'JSON Structure', icon: <FileJson size={18} /> },
                  ].map(f => (
                    <button 
                      key={f.id}
                      onClick={() => setExportOptions({...exportOptions, format: f.id})}
                      className={`flex items-center gap-3 p-3 rounded-xl border text-sm font-bold transition-all ${exportOptions.format === f.id ? 'bg-indigo-50 border-indigo-500 text-indigo-700' : 'border-slate-200 text-slate-600 hover:bg-slate-50'}`}
                    >
                      {f.icon} {f.label}
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Columns to Include</label>
                <div className="flex flex-wrap gap-2">
                  {['Description', 'Quantity', 'Unit', 'Rate', 'Total', 'Confidence', 'Reasoning'].map(col => (
                    <button 
                      key={col}
                      onClick={() => {
                        const newCols = exportOptions.columns.includes(col) 
                          ? exportOptions.columns.filter(c => c !== col) 
                          : [...exportOptions.columns, col];
                        setExportOptions({...exportOptions, columns: newCols});
                      }}
                      className={`px-3 py-1.5 rounded-lg text-xs font-bold border transition-all ${exportOptions.columns.includes(col) ? 'bg-slate-900 border-slate-900 text-white' : 'border-slate-200 text-slate-500 hover:bg-slate-50'}`}
                    >
                      {col}
                    </button>
                  ))}
                </div>
              </div>
            </div>
            <div className="p-6 bg-slate-50 flex gap-3 border-t border-slate-100">
              <button onClick={() => setShowExportModal(false)} className="flex-1 py-3 text-sm font-bold text-slate-500 hover:bg-slate-100 rounded-xl transition-colors">CANCEL</button>
              <button className="flex-1 py-3 text-sm font-bold bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center justify-center gap-2">
                <Download size={18} /> EXPORT
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const TrendingUp = ({ className, size = 24 }: { className?: string; size?: number }) => (
  <svg 
    className={className} 
    width={size} 
    height={size} 
    fill="none" 
    viewBox="0 0 24 24" 
    stroke="currentColor" 
    strokeWidth={3}
  >
    <path strokeLinecap="round" strokeLinejoin="round" d="M13 7h8m0 0v8m0-8l-9 9-4-4-6 6" />
  </svg>
);

import React from 'react';
import { NAV_ITEMS } from '../constants';
import { UserRole } from '../types';
import { HardHat, LogOut, ChevronDown, UserCircle, Briefcase, GraduationCap, ShieldCheck } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  onTabChange: (id: string) => void;
  userRole: UserRole;
  setUserRole: (role: UserRole) => void;
}

