import React, { useState, useRef } from 'react';
import { Project, BOQItem, DesignError, SteelDetail } from '../types';
import { 
  ArrowLeft, Upload, FileText, Activity, ShieldAlert, Cpu, 
  Volume2, Download, Package, PieChart as PieChartIcon, 
  X, CheckCircle, Plus, TrendingUp, HelpCircle, ShieldCheck, Edit3, MapPin, Square
} from 'lucide-react';
import { BOQTable } from './BOQTable';
import { ErrorDetector } from './ErrorDetector';
import { WhatIfSimulator } from './WhatIfSimulator';
import { geminiService, decodeBase64, decodeAudioData } from '../services/gemini';
import { MOCK_BOQ, MOCK_STEEL_DETAILS } from '../constants';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface ProjectDetailsProps {
  project: Project;
  onBack: () => void;
  userRole: string;
  updateProject: (p: Project) => void;
}

export const ProjectDetails: React.FC<ProjectDetailsProps> = ({ project, onBack, userRole, updateProject }) => {
  const [activeSubTab, setActiveSubTab] = useState<'boq' | 'steel' | 'costs' | 'errors' | 'what-if'>('boq');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [analysisPhase, setAnalysisPhase] = useState('');
  const [boqData, setBoqData] = useState<BOQItem[]>(project.boq || MOCK_BOQ);
  const [steelDetails, setSteelDetails] = useState<SteelDetail[]>(MOCK_STEEL_DETAILS);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);
  const [showExportModal, setShowExportModal] = useState(false);
  const [showSteelManualModal, setShowSteelManualModal] = useState(false);
  const [exportOptions, setExportOptions] = useState({ format: 'pdf', columns: ['Description', 'Quantity', 'Rate', 'Total'] });

  const [newSteel, setNewSteel] = useState({ barMark: '', diameter: 16, spacing: 150, shape: 'Straight', totalWeight: 0 });
  const audioRef = useRef<AudioBufferSourceNode | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);

  const roleColor = userRole === 'Contractor' ? 'amber' : userRole === 'Student' ? 'emerald' : 'indigo';
  const COLORS = ['#4F46E5', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6'];

  const getCostData = () => {
    const categories: Record<string, number> = {};
    boqData.forEach(item => {
      categories[item.category] = (categories[item.category] || 0) + item.total;
    });
    return Object.entries(categories).map(([name, value]) => ({ name, value }));
  };

  const toBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result?.toString().split(',')[1] || "");
      reader.onerror = error => reject(error);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    await performAnalysis(file);
  };

  const performAnalysis = async (file?: File) => {
    setIsAnalyzing(true);
    setUploadProgress(0);

    const phases = [
      { msg: 'Detecting walls and columns...', progress: 15 },
      { msg: 'Parsing reinforcement layers...', progress: 35 },
      { msg: 'Calculating material volumes...', progress: 55 },
      { msg: 'Validating IS:456 compliance...', progress: 80 },
      { msg: 'Refining quantity takeoff...', progress: 95 },
      { msg: 'Finalizing Engineering Brain...', progress: 100 },
    ];

    for (const phase of phases) {
      setAnalysisPhase(phase.msg);
      await new Promise(r => setTimeout(r, 600));
      setUploadProgress(phase.progress);
    }

    try {
      let base64 = "";
      if (file) {
        base64 = await toBase64(file);
      } else {
        // Mock re-analyze behavior using default random image data or just re-running on existing
        base64 = ""; 
      }

      if (base64) {
        const result = await geminiService.analyzeDrawing(base64, `${project.buildingType} with ${project.floors} floors`);
        if (result.boq.length > 0) {
          setBoqData(result.boq);
          updateProject({ ...project, boq: result.boq, errors: result.errors, status: 'Analyzed' });
        }
      } else {
        // If no file (re-analyze), just use mock data refresh
        setBoqData(MOCK_BOQ);
        updateProject({ ...project, boq: MOCK_BOQ, status: 'Analyzed' });
      }
    } catch (err) {
      console.error("Analysis Error:", err);
      alert("AI Analysis encountered an error. Reverting to baseline estimates.");
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleVoiceExplanation = async () => {
    if (isPlayingAudio) {
      stopAudio();
      return;
    }

    setIsPlayingAudio(true);
    const summaryText = `Acting as a Senior ${userRole === 'Contractor' ? 'Procurement Lead' : userRole === 'Student' ? 'Professor' : 'Consultant'}. 
    Analyzing project ${project.name}. The total estimated cost is ${getCostData().reduce((a,b) => a + b.value, 0).toLocaleString()} dollars.
    Confidence for concrete extraction is 98 percent. Notice the structural reinforcement requirements for the 12th floor shear walls.`;

    try {
      const audioBase64 = await geminiService.generateSpeech(summaryText);
      if (audioBase64) {
        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        audioCtxRef.current = audioContext;
        const decodedBytes = decodeBase64(audioBase64);
        const audioBuffer = await decodeAudioData(decodedBytes, audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContext.destination);
        source.onended = () => {
          setIsPlayingAudio(false);
          audioRef.current = null;
        };
        audioRef.current = source;
        source.start();
      } else {
        setIsPlayingAudio(false);
      }
    } catch (e) {
      console.error(e);
      setIsPlayingAudio(false);
    }
  };

  const stopAudio = () => {
    if (audioRef.current) {
      audioRef.current.stop();
      audioRef.current = null;
    }
    if (audioCtxRef.current) {
      audioCtxRef.current.close();
      audioCtxRef.current = null;
    }
    setIsPlayingAudio(false);
  };

  const handleAddSteel = () => {
    const id = 'st_' + (steelDetails.length + 1);
    setSteelDetails([...steelDetails, { ...newSteel, id }]);
    setShowSteelManualModal(false);
    setNewSteel({ barMark: '', diameter: 16, spacing: 150, shape: 'Straight', totalWeight: 0 });
  };

  const handleExport = () => {
    alert(`Exporting BOQ in ${exportOptions.format.toUpperCase()} format...\nColumns: ${exportOptions.columns.join(', ')}`);
    setShowExportModal(false);
  };

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Detail Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <button onClick={onBack} className="p-3 bg-white hover:bg-slate-100 border border-slate-200 rounded-2xl transition-all shadow-sm text-slate-500 hover:text-indigo-600">
            <ArrowLeft size={20} />
          </button>
          <div>
            <div className="flex items-center gap-2 mb-1">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">{project.name}</h2>
              <span className={`bg-${roleColor}-100 text-${roleColor}-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-${roleColor}-200`}>
                {userRole} Mode
              </span>
            </div>
            <div className="flex items-center gap-2 text-slate-400 text-sm font-bold">
              <MapPin size={14} />
              <span>{project.location}</span>
              <span className="text-slate-200">|</span>
              <span>{project.floors} Floors</span>
            </div>
          </div>
        </div>
        <div className="flex items-center gap-3">
           <button 
             onClick={handleVoiceExplanation}
             className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-sm font-black border transition-all ${isPlayingAudio ? `bg-${roleColor}-600 border-${roleColor}-600 text-white shadow-xl shadow-${roleColor}-500/30` : 'bg-white border-slate-200 text-slate-700 hover:border-indigo-400 shadow-sm'}`}
           >
             {isPlayingAudio ? <Square size={20} className="fill-current" /> : <Volume2 size={20} />}
             {isPlayingAudio ? 'Stop Explanation' : 'Audio Analysis'}
           </button>
           <button 
             onClick={() => setShowExportModal(true)}
             className="flex items-center gap-2 px-6 py-3 rounded-2xl bg-slate-900 text-white text-sm font-black hover:bg-slate-800 shadow-2xl transition-all"
           >
             <Download size={20} />
             Export BOQ
           </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Drawing & Metadata Sidebar */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white p-3 rounded-[2.5rem] border border-slate-200 shadow-sm aspect-square relative group overflow-hidden">
            {isAnalyzing && (
              <div className="absolute inset-0 z-20 bg-slate-900/80 backdrop-blur-xl flex flex-col items-center justify-center text-white p-8 text-center">
                <div className="relative w-24 h-24 mb-6">
                   <div className="absolute inset-0 flex items-center justify-center font-black text-2xl text-white">{uploadProgress}%</div>
                   <div className="absolute inset-0 border-4 border-white/10 rounded-full" />
                   <div className="absolute inset-0 border-4 border-indigo-400 rounded-full border-t-transparent animate-spin duration-700" />
                </div>
                <p className="font-black text-sm tracking-[0.2em] uppercase mb-4 text-indigo-300">{analysisPhase}</p>
              </div>
            )}
            <img 
              src={project.drawingUrl || 'https://picsum.photos/600/600'} 
              className="w-full h-full object-cover rounded-[2rem] shadow-inner brightness-95"
            />
            <div className="absolute inset-0 bg-slate-900/60 opacity-0 group-hover:opacity-100 transition-all flex items-center justify-center">
               <label className="cursor-pointer bg-white text-slate-900 text-[10px] font-black tracking-widest uppercase px-8 py-4 rounded-2xl shadow-2xl hover:scale-110 transition-all">
                  <input type="file" className="hidden" onChange={handleFileUpload} accept=".dwg,.dxf,.jpg,.png" />
                  Replace Drawing
               </label>
            </div>
          </div>

          <div className="bg-slate-900 rounded-[2rem] p-8 text-white space-y-8 shadow-2xl shadow-slate-200">
            <h4 className="text-[10px] font-black text-indigo-400 uppercase tracking-[0.3em]">AI Diagnostics</h4>
            <div className="space-y-6">
               <div className="flex items-center justify-between text-xs">
                 <span className="text-slate-500 font-bold uppercase tracking-wider">Analysis Status</span>
                 <div className="flex items-center gap-2">
                   <span className="font-black text-slate-100">{project.status}</span>
                   <CheckCircle className="text-green-400" size={16} />
                 </div>
               </div>
            </div>
            <div className="pt-4 border-t border-slate-800">
               <button 
                 onClick={() => performAnalysis()}
                 disabled={isAnalyzing}
                 className="w-full bg-indigo-600 hover:bg-indigo-500 py-4 rounded-2xl font-black text-xs uppercase tracking-[0.2em] transition-all disabled:opacity-50"
               >
                 {isAnalyzing ? 'Analyzing...' : 'Re-Analyze'}
               </button>
            </div>
          </div>
        </div>

        {/* Tab Content Area */}
        <div className="lg:col-span-3 space-y-6">
          <div className="flex bg-slate-100 p-1.5 rounded-3xl w-fit overflow-x-auto border border-slate-200 shadow-inner">
            {[
              { id: 'boq', label: 'Takeoff BOQ', icon: <FileText size={18} /> },
              { id: 'steel', label: 'Reinforcement', icon: <Package size={18} /> },
              { id: 'costs', label: 'Cost Analysis', icon: <PieChartIcon size={18} /> },
              { id: 'errors', label: 'Error Detector', icon: <ShieldAlert size={18} /> },
              { id: 'what-if', label: 'Simulate', icon: <Activity size={18} /> },
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveSubTab(tab.id as any)}
                className={`flex items-center gap-2 px-6 py-3 rounded-2xl text-sm font-black transition-all ${
                  activeSubTab === tab.id ? 'bg-white text-indigo-600 shadow-xl' : 'text-slate-500 hover:text-slate-800'
                }`}
              >
                {tab.icon}
                {tab.label}
              </button>
            ))}
          </div>

          <div className="bg-white rounded-[2.5rem] border border-slate-200 shadow-2xl shadow-slate-100 overflow-hidden min-h-[600px]">
            {activeSubTab === 'boq' && <BOQTable items={boqData} />}

            {activeSubTab === 'steel' && (
              <div className="p-10 space-y-10 animate-in slide-in-from-right-8 duration-500">
                <div className="flex flex-col md:flex-row justify-between items-start gap-4">
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tighter">Steel Reinforcement Detailing</h3>
                    <p className="text-sm text-slate-500 font-medium mt-1">Directly extracted from Bar Bending Schedule (BBS) drawings.</p>
                  </div>
                  <div className="flex gap-3 shrink-0">
                    <button 
                      onClick={() => setShowSteelManualModal(true)}
                      className="flex items-center gap-2 bg-white border border-slate-200 text-slate-800 px-5 py-2.5 rounded-2xl text-xs font-black hover:bg-slate-50 shadow-sm"
                    >
                      <Edit3 size={16} /> MANUAL INPUT
                    </button>
                  </div>
                </div>

                <div className="border border-slate-100 rounded-[2rem] overflow-hidden">
                  <table className="w-full text-left">
                    <thead className="bg-slate-50 border-b border-slate-200">
                      <tr>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Bar Mark</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Dia (mm)</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Spacing</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Shape</th>
                        <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Net Wt (MT)</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-100">
                      {steelDetails.map(bar => (
                        <tr key={bar.id} className="hover:bg-slate-50 transition-all group">
                          <td className="px-8 py-5 text-sm font-black text-slate-900">{bar.barMark}</td>
                          <td className="px-8 py-5 text-sm font-bold text-slate-600 text-center">{bar.diameter}mm</td>
