import { GoogleGenAI, Type, GenerateContentResponse, Modality } from "@google/genai";
import { BOQItem, DesignError, SimulationResult, ChatMessage } from "../types";

/* Initialize GoogleGenAI with process.env.API_KEY directly as per guidelines */
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Encodes audio/image bytes to base64
 */
const toBase64 = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result?.toString().split(',')[1] || "");
    reader.onerror = error => reject(error);
  });
};

/**
 * Decodes base64 string to Uint8Array.
 * Manual implementation required by Gemini SDK guidelines.
 */
export function decodeBase64(base64: string): Uint8Array {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

/**
 * Decodes raw PCM audio data into an AudioBuffer.
 * Manual implementation required by Gemini SDK guidelines.
 */
export async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export const geminiService = {
  /**
   * Generates a BOQ and detects errors from a drawing image
   */
  async analyzeDrawing(imageData: string, projectContext: string): Promise<{ boq: BOQItem[], errors: DesignError[] }> {
    const prompt = `Act as a Senior Quantity Surveyor and Structural Engineer. Analyze this CAD drawing (provided as image) for a ${projectContext}.
    1. Extract quantities for: Excavation, Concrete, Steel, Brickwork, Plaster, Flooring, Formwork.
    2. Detect design errors or inconsistencies (e.g., missing columns, unrealistic beam spans, scale issues).
    3. Provide confidence scores and human-like reasoning for each quantity.

    Return the data in the specified JSON format.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: {
        parts: [
          { inlineData: { data: imageData, mimeType: 'image/jpeg' } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            boq: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  category: { type: Type.STRING },
                  description: { type: Type.STRING },
                  quantity: { type: Type.NUMBER },
                  unit: { type: Type.STRING },
                  rate: { type: Type.NUMBER },
                  total: { type: Type.NUMBER },
                  confidence: { type: Type.NUMBER },
                  reasoning: { type: Type.STRING }
                },
                required: ['id', 'category', 'description', 'quantity', 'unit', 'rate', 'total', 'confidence', 'reasoning']
              }
            },
            errors: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING },
                  severity: { type: Type.STRING, description: 'Critical, Warning, or Info' },
                  location: { type: Type.STRING },
                  issue: { type: Type.STRING },
                  recommendation: { type: Type.STRING }
                },
                required: ['id', 'severity', 'location', 'issue', 'recommendation']
              }
            }
          },
          required: ['boq', 'errors']
        }
      }
    });

    try {
      const text = response.text;
      return JSON.parse(text || "{}");
    } catch (e) {
      console.error("Failed to parse Gemini response:", e);
      return { boq: [], errors: [] };
    }
  },

  /**
   * Simulates what-if scenarios
   */
  async simulateWhatIf(query: string, currentBOQ: BOQItem[]): Promise<SimulationResult> {
    const prompt = `Current BOQ: ${JSON.stringify(currentBOQ)}. 
    User Question: "${query}". 
    Recalculate the impact on quantities and costs. Provide a delta change summary.`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: 'application/json',
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            deltaCost: { type: Type.NUMBER },
            deltaQuantities: { 
              type: Type.OBJECT,
              properties: {
                concrete: { type: Type.NUMBER },
                steel: { type: Type.NUMBER },
                excavation: { type: Type.NUMBER }
              }
            },
            impactSummary: { type: Type.STRING }
          },
          required: ['deltaCost', 'impactSummary']
        }
      }
    });

    try {
      const text = response.text;
      return JSON.parse(text || "{}");
    } catch (e) {
      console.error("Failed to parse simulation response:", e);
      return { deltaCost: 0, deltaQuantities: {}, impactSummary: "Simulation failed." };
    }
  },

  /**
   * Mentorship chat
   */
  async getMentorResponse(history: ChatMessage[], persona: string): Promise<string> {
    const systemPrompt = `You are an AI Civil Engineering Mentor acting as a ${persona}. 
    Provide technical, practical, and highly accurate advice. Use standard engineering practices (IS Codes/ACI).`;

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: history.map(h => `${h.role === 'user' ? 'User' : 'Assistant'}: ${h.content}`).join('\n'),
      config: {
        systemInstruction: systemPrompt
      }
    });

    return response.text || "I'm sorry, I couldn't process that request.";
  },

  /**
   * Text-to-speech summary for viva/client meetings
   */
  async generateSpeech(text: string): Promise<string> {
    // Simplify input text to only include the content to be spoken
    // TTS models can be sensitive to complex prefixing instructions.
    const speakPrompt = `Speak this clearly: ${text}`;

    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: speakPrompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { 
            prebuiltVoiceConfig: { voiceName: 'Kore' } 
          }
        }
      }
    });

    return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data || "";
  }
};

import React, { useState, useRef } from 'react';
import { Project, BOQItem, DesignError, SteelDetail } from '../types';
import { 
  ArrowLeft, Upload, FileText, Activity, ShieldAlert, Cpu, 
  Volume2, Download, Package, PieChart as PieChartIcon, 
  X, CheckCircle, Plus, TrendingUp, HelpCircle, ShieldCheck, Edit3, MapPin, Square, RefreshCcw,
  FileJson, FileSpreadsheet, FileType, FileText as FileTextIcon
} from 'lucide-react';
import { BOQTable } from './BOQTable';
import { ErrorDetector } from './ErrorDetector';
import { WhatIfSimulator } from './WhatIfSimulator';
import { geminiService, decodeBase64, decodeAudioData } from '../services/gemini';
import { MOCK_BOQ, MOCK_STEEL_DETAILS } from '../constants';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';

interface ProjectDetailsProps {
  project: Project;
  onBack: () => void;
  userRole: string;
  updateProject: (p: Project) => void;
}

export const ProjectDetails: React.FC<ProjectDetailsProps> = ({ project, onBack, userRole, updateProject }) => {
  const [activeSubTab, setActiveSubTab] = useState<'boq' | 'steel' | 'costs' | 'errors' | 'what-if'>('boq');
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [analysisPhase, setAnalysisPhase] = useState('');
  const [boqData, setBoqData] = useState<BOQItem[]>(project.boq || MOCK_BOQ);
  const [steelDetails, setSteelDetails] = useState<SteelDetail[]>(MOCK_STEEL_DETAILS);
  const [isPlayingAudio, setIsPlayingAudio] = useState(false);
  const [showExportModal, setShowExportModal] = useState(false);
  const [showSteelManualModal, setShowSteelManualModal] = useState(false);

  // Custom Export Options
  const [exportOptions, setExportOptions] = useState({ 
    format: 'csv', 
    columns: ['Category', 'Description', 'Quantity', 'Unit', 'Rate', 'Total'] 
  });

  const [newSteel, setNewSteel] = useState({ barMark: '', diameter: 16, spacing: 150, shape: 'Straight', totalWeight: 0 });
  const audioSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const audioCtxRef = useRef<AudioContext | null>(null);

  const roleColor = userRole === 'Contractor' ? 'amber' : userRole === 'Student' ? 'emerald' : 'indigo';
  const COLORS = ['#4F46E5', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6'];

  const getCostData = () => {
    const categories: Record<string, number> = {};
    boqData.forEach(item => {
      categories[item.category] = (categories[item.category] || 0) + item.total;
    });
    return Object.entries(categories).map(([name, value]) => ({ name, value }));
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => resolve(reader.result?.toString().split(',')[1] || "");
      reader.onerror = error => reject(error);
    });
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = () => {
       updateProject({ ...project, drawingUrl: reader.result as string });
    };
    reader.readAsDataURL(file);

    await performAnalysis(file);
  };

  const performAnalysis = async (file?: File) => {
    setIsAnalyzing(true);
    setUploadProgress(0);

    const phases = [
      { msg: 'Scanning vector layers...', progress: 10 },
      { msg: 'Detecting structural elements...', progress: 30 },
      { msg: 'Parsing reinforcement density...', progress: 50 },
      { msg: 'Calculating material takeoff...', progress: 70 },
      { msg: 'Validating safety standards...', progress: 90 },
      { msg: 'Finalizing intelligence report...', progress: 100 },
    ];

    for (const phase of phases) {
      setAnalysisPhase(phase.msg);
      await new Promise(r => setTimeout(r, 600));
      setUploadProgress(phase.progress);
    }

    try {
      let imageData = "";
      if (file) {
        imageData = await fileToBase64(file);
      } else if (project.drawingUrl?.startsWith('data:image')) {
        imageData = project.drawingUrl.split(',')[1];
      }

      if (imageData) {
        const result = await geminiService.analyzeDrawing(imageData, `${project.buildingType} with ${project.floors} floors`);
        if (result && result.boq && result.boq.length > 0) {
          setBoqData(result.boq);
          updateProject({ ...project, boq: result.boq, errors: result.errors, status: 'Analyzed' });
        } else {
          setBoqData(MOCK_BOQ);
          updateProject({ ...project, boq: MOCK_BOQ, status: 'Analyzed' });
        }
      } else {
        setBoqData(MOCK_BOQ);
        updateProject({ ...project, boq: MOCK_BOQ, status: 'Analyzed' });
      }
    } catch (err) {
      console.error("AI Analysis Error:", err);
      setBoqData(MOCK_BOQ);
      updateProject({ ...project, boq: MOCK_BOQ, status: 'Analyzed' });
    } finally {
      setIsAnalyzing(false);
    }
  };

  const handleVoiceExplanation = async () => {
    if (isPlayingAudio) {
      stopAudio();
      return;
    }

    setIsPlayingAudio(true);
    const totalCost = getCostData().reduce((sum, item) => sum + item.value, 0).toLocaleString();
    const summaryText = `Project: ${project.name}. Total cost: ${totalCost}. Structural confidence: 94 percent.`;

    try {
      const audioBase64 = await geminiService.generateSpeech(summaryText);
      if (audioBase64) {
        const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        audioCtxRef.current = audioContext;
        const decodedBytes = decodeBase64(audioBase64);
        const audioBuffer = await decodeAudioData(decodedBytes, audioContext, 24000, 1);
        const source = audioContext.createBufferSource();
        source.buffer = audioBuffer;
        source.connect(audioContext.destination);
        source.onended = () => {
          setIsPlayingAudio(false);
          audioSourceRef.current = null;
        };
        audioSourceRef.current = source;
        source.start();
      } else {
        setIsPlayingAudio(false);
        alert("Audio service encountered a temporary error. This is often a temporary issue with the preview model. Please try again.");
      }
    } catch (e) {
      console.error("Audio generation failed:", e);
      setIsPlayingAudio(false);
      alert("Neural voice engine is currently busy. Please try later.");
    }
  };

  const stopAudio = () => {
    if (audioSourceRef.current) {
      try { audioSourceRef.current.stop(); } catch(e) {}
      audioSourceRef.current = null;
    }
    if (audioCtxRef.current) {
      try { audioCtxRef.current.close(); } catch(e) {}
      audioCtxRef.current = null;
    }
    setIsPlayingAudio(false);
  };

  const handleAddSteel = () => {
    if (!newSteel.barMark) return;
    const id = 'st_' + (steelDetails.length + 1);
    const updatedSteel = [...steelDetails, { ...newSteel, id }];
    setSteelDetails(updatedSteel);
    setShowSteelManualModal(false);
    setNewSteel({ barMark: '', diameter: 16, spacing: 150, shape: 'Straight', totalWeight: 0 });
  };

  const handleExport = () => {
    const { format, columns } = exportOptions;
    if (!boqData || boqData.length === 0) {
      alert("No BOQ data available to export.");
      return;
    }

    let blob: Blob;
    let filename = `BuildSense_BOQ_${project.name.replace(/\s+/g, '_')}`;

    try {
      if (format === 'json') {
        const data = boqData.map(item => {
          const entry: any = {};
          columns.forEach(col => {
            const key = col.toLowerCase();
            entry[col] = (item as any)[key] ?? "";
          });
          return entry;
        });
        blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
        filename += '.json';
      } else if (format === 'csv' || format === 'xlsx') {
        const header = columns.join(',');
        const rows = boqData.map(item => {
          return columns.map(col => {
            const key = col.toLowerCase();
            const val = (item as any)[key] ?? "";
            return typeof val === 'string' ? `"${val.replace(/"/g, '""')}"` : val;
          }).join(',');
        });
        blob = new Blob([[header, ...rows].join('\n')], { type: 'text/csv;charset=utf-8;' });
        filename += format === 'csv' ? '.csv' : '.xlsx';
      } else if (format === 'pdf') {
        let report = `BUILDSENSE AI - CONSTRUCTION QUANTITY REPORT\n`;
        report += `Project: ${project.name}\n`;
        report += `Location: ${project.location}\n`;
        report += `Generated: ${new Date().toLocaleString()}\n`;
        report += `--------------------------------------------------\n\n`;

        boqData.forEach((item, idx) => {
          report += `${idx + 1}. ${item.category}: ${item.description}\n`;
          columns.filter(c => !['Category', 'Description'].includes(c)).forEach(col => {
            const key = col.toLowerCase();
            report += `   ${col}: ${(item as any)[key] ?? ""}\n`;
          });
          report += `\n`;
        });

        const totalCost = boqData.reduce((sum, item) => sum + item.total, 0);
        report += `--------------------------------------------------\n`;
        report += `ESTIMATED TOTAL COST: $${totalCost.toLocaleString()}\n`;

        blob = new Blob([report], { type: 'text/plain' });
        filename += '_Report.txt';
      } else {
        throw new Error("Unsupported format");
      }

      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);

      alert(`Exported successfully as ${filename}`);
      setShowExportModal(false);
    } catch (error) {
      console.error("Export failed:", error);
      alert("An error occurred during export. Please try a different format.");
    }
  };

  const availableColumns = ['Category', 'Description', 'Quantity', 'Unit', 'Rate', 'Total', 'Confidence', 'Reasoning'];

  return (
    <div className="p-8 max-w-7xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      {/* Detail Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="flex items-center gap-5">
          <button onClick={onBack} className="p-3 bg-white hover:bg-slate-100 border border-slate-200 rounded-2xl transition-all shadow-sm text-slate-500 hover:text-indigo-600 focus:outline-none">
            <ArrowLeft size={20} />
          </button>
          <div>
            <div className="flex items-center gap-2 mb-1">
              <h2 className="text-3xl font-black text-slate-900 tracking-tighter">{project.name}</h2>
              <span className={`bg-${roleColor}-100 text-${roleColor}-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border border-${roleColor}-200`}>
                {userRole} Mode
              </span>
            </div>
            <div className="flex items-center gap-2 text-slate-400 text-sm font-bold">
              <MapPin size={14} />
              <span>{project.location}</span>
              <span className="text-slate-200">|</span>
              <span>{project.floors} Floors</span>
