import React, { useState } from 'react';
import { Project, UserRole, ProjectTemplate } from '../types';
import { 
  Plus, MapPin, Building2, TrendingUp, AlertCircle, 
  FileSpreadsheet, ClipboardList, LayoutTemplate, 
  ArrowRight, Zap, Save, Briefcase, GraduationCap, X, CheckCircle
} from 'lucide-react';
import { AreaChart, Area, Tooltip, ResponsiveContainer, XAxis, CartesianGrid } from 'recharts';

interface DashboardProps {
  projects: Project[];
  templates: ProjectTemplate[];
  onSelectProject: (id: string) => void;
  userRole: UserRole;
  addProject: (p: Project) => void;
  addTemplate: (t: ProjectTemplate) => void;
}

const MOCK_CHART_DATA = [
  { name: 'Week 1', cost: 4000 },
  { name: 'Week 2', cost: 3000 },
  { name: 'Week 3', cost: 5000 },
  { name: 'Week 4', cost: 4500 },
  { name: 'Week 5', cost: 6000 },
  { name: 'Week 6', cost: 5500 },
];

export const Dashboard: React.FC<DashboardProps> = ({ projects, templates, onSelectProject, userRole, addProject, addTemplate }) => {
  const [showTemplateModal, setShowTemplateModal] = useState(false);
  const [newTemplate, setNewTemplate] = useState({ name: '', type: 'Residential', floors: 1 });

  const getRoleMetrics = () => {
    switch(userRole) {
      case 'Contractor':
        return [
          { label: 'Procurement Total', value: '$82.4M', icon: <Briefcase className="text-amber-600" />, trend: 'Materials + Labor' },
          { label: 'Resource Efficiency', value: '94%', icon: <TrendingUp className="text-amber-600" />, trend: 'Above target' },
          { label: 'Active Crew Count', value: '342', icon: <Plus className="text-amber-600" />, trend: 'On-site today' },
          { label: 'Equipment Uptime', value: '88%', icon: <Zap className="text-amber-600" />, trend: 'In operation' },
        ];
      case 'Student':
        return [
          { label: 'Learning Progress', value: '72%', icon: <GraduationCap className="text-emerald-600" />, trend: 'BOQ Module' },
          { label: 'Solved Case Studies', value: '12', icon: <Building2 className="text-emerald-600" />, trend: 'Last 30 days' },
          { label: 'AI Mentorship Hrs', value: '24', icon: <Zap className="text-emerald-600" />, trend: 'Interaction' },
          { label: 'Certifications', value: '02', icon: <ClipboardList className="text-emerald-600" />, trend: 'Verified' },
        ];
      default:
        return [
          { label: 'Engineering Value', value: '$162.5M', icon: <TrendingUp className="text-indigo-600" />, trend: 'Structural BOQ' },
          { label: 'Safety Index', value: '98.2', icon: <ClipboardList className="text-indigo-600" />, trend: 'Compliance high' },
          { label: 'Design Alerts', value: '04', icon: <AlertCircle className="text-indigo-600" />, trend: 'Critical review' },
          { label: 'Cloud Storage', value: '4.2 GB', icon: <FileSpreadsheet className="text-indigo-600" />, trend: 'CAD Assets' },
        ];
    }
  };

  const handleDeployTemplate = (template: ProjectTemplate) => {
    const newPrj: Project = {
      id: `prj_${Date.now()}`,
      name: `${template.name} Project`,
      location: 'Site Location TBD',
      buildingType: template.buildingType,
      floors: template.floors,
      budget: 50000000,
      timeline: '12 Months',
      status: 'Draft',
      createdAt: new Date(),
      drawingUrl: 'https://picsum.photos/800/600?random=' + Math.floor(Math.random() * 100),
    };
    addProject(newPrj);
    alert(`Successfully deployed template: ${template.name}. A new project has been created.`);
  };

  const handleCreateTemplate = () => {
    if (!newTemplate.name.trim()) {
      alert("Please enter a template name.");
      return;
    }
    const t: ProjectTemplate = {
      id: `t_${Date.now()}`,
      name: newTemplate.name,
      buildingType: newTemplate.type,
      floors: newTemplate.floors,
      description: `User-defined template for ${newTemplate.type} structures.`,
      baseBoq: []
    };
    addTemplate(t);
    setShowTemplateModal(false);
    setNewTemplate({ name: '', type: 'Residential', floors: 1 });
  };

  const handleDownloadMasterReport = () => {
    // Generate a real CSV file for download
    const header = "Project ID,Name,Location,Status,Budget,Floors,Type\n";
    const rows = projects.map(p => 
      `${p.id},"${p.name}","${p.location}",${p.status},${p.budget},${p.floors},${p.buildingType}`
    ).join("\n");

    const csvContent = "\ufeff" + header + rows;
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    a.download = `BuildSense_Intelligence_Report_${new Date().toISOString().split('T')[0]}.csv`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    alert("Master Intelligence Report downloaded successfully.");
  };

  const roleColor = userRole === 'Contractor' ? 'amber' : userRole === 'Student' ? 'emerald' : 'indigo';

  return (
    <div className="p-8 space-y-8 max-w-7xl mx-auto animate-in fade-in duration-700">
      {/* Metrics */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {getRoleMetrics().map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:shadow-xl transition-all hover:-translate-y-1">
            <div className="flex justify-between items-start mb-4">
              <div className={`p-2.5 bg-${roleColor}-50 rounded-xl`}>{stat.icon}</div>
              <span className="text-[10px] font-bold text-slate-400 uppercase">{stat.trend}</span>
            </div>
            <p className="text-xs font-bold text-slate-400 uppercase tracking-wider">{stat.label}</p>
            <h3 className="text-3xl font-black text-slate-900 mt-1">{stat.value}</h3>
          </div>
        ))}
