                    onChange={(e) => setNewTemplate({...newTemplate, floors: parseInt(e.target.value) || 1})}
                    className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 font-bold"
                  />
