               <button onClick={() => setShowTemplateModal(false)} className="flex-1 py-4 text-xs font-black text-slate-500 uppercase tracking-widest focus:outline-none">Cancel</button>
               <button 
                 onClick={handleCreateTemplate}
                 className={`flex-1 py-4 text-xs font-black bg-${roleColor}-600 text-white rounded-2xl uppercase tracking-widest shadow-xl shadow-${roleColor}-500/20 active:scale-95 focus:outline-none`}
